const seen = new Set();
const officeOptions = [];
const jobTitles = [];
const employeeSeen = new Set();
const employeeOptions = [];

for (const item of $input.all()) {
  const company  = String(item.json.company          ?? '').trim();
  const street   = String(item.json.streetAddress    ?? '').trim();
  const city     = String(item.json.l                ?? '').trim();
  const state    = String(item.json.st               ?? '').trim();
  const zip      = String(item.json.postalCode       ?? '').trim();
  const phone    = String(item.json.telephoneNumber  ?? '').trim();
  const title    = String(item.json.title            ?? '').trim();

  if (company && city && phone) {
    const key = `${company}~~${city}~~${phone}`;
    if (!seen.has(key)) {
      seen.add(key);
      const option = `${company} — ${city} ~~ ${street} ~~ ${city} ~~ ${state} ~~ ${zip} ~~ ${phone}`;
      officeOptions.push({ company, city, option });
    }
  }

  if (title) jobTitles.push(title);

  const cn = String(item.json.cn ?? '').trim();
  const sam = String(item.json.sAMAccountName ?? '').trim();
  if (cn && sam && !employeeSeen.has(sam)) {
    employeeSeen.add(sam);
    employeeOptions.push({ cn, sam, option: `${cn} (${sam})` });
  }
}

employeeOptions.sort((a, b) => a.cn.localeCompare(b.cn));

officeOptions.sort((a, b) => {
  const cmp = a.company.localeCompare(b.company);
  return cmp !== 0 ? cmp : a.city.localeCompare(b.city);
});

const uniqueJobTitles = [...new Set(jobTitles)]
  .sort((a, b) => a.localeCompare(b))
  .map(t => ({ option: t }));

if (officeOptions.length === 0) throw new Error('No office location options built.');
if (uniqueJobTitles.length === 0) throw new Error('No job title options built.');

return [{
  json: {
    dropdownOptions: {
      officeLocation: officeOptions.map(o => ({ option: o.option })),
      jobTitle: uniqueJobTitles,
      existingEmployee: employeeOptions.map(o => ({ option: o.option }))
    }
  }
}];

const items = $input.all();

const optionsItem = items.find(item => item.json.dropdownOptions && item.json.dropdownOptions.jobTitle);
const groupsItem = items.find(item => item.json.dropdownOptions && item.json.dropdownOptions.groups);
const workflowItem = items.find(item => Array.isArray(item.json.nodes));

if (!optionsItem) throw new Error('Could not find dropdownOptions input.');
if (!groupsItem) throw new Error('Could not find groups dropdownOptions input.');
if (!workflowItem) throw new Error('Could not find workflow JSON input.');

const dropdownOptions = optionsItem.json.dropdownOptions;
const groupOptions = groupsItem.json.dropdownOptions.groups;
const workflow = workflowItem.json;

const TARGET_FORM_TRIGGER_NAME = 'On form submission';
const formTriggerNode = workflow.nodes.find(node => node.name === TARGET_FORM_TRIGGER_NAME);

if (!formTriggerNode) throw new Error(`Could not find form trigger node named "${TARGET_FORM_TRIGGER_NAME}" in target workflow.`);

formTriggerNode.parameters.formFields = {
  values: [
    {
      fieldLabel: 'Existing Employee',
      fieldType: 'dropdown',
      fieldOptions: { values: dropdownOptions.existingEmployee }
    },
    { fieldLabel: 'First Name' },
    { fieldLabel: 'Last Name' },
    {
      fieldLabel: 'Job Title',
      fieldType: 'dropdown',
      fieldOptions: { values: dropdownOptions.jobTitle }
    },
    {
      fieldLabel: 'Studio',
      fieldType: 'dropdown',
      fieldOptions: { values: dropdownOptions.officeLocation }
    },
    { fieldLabel: 'EMP ID' },
    { fieldLabel: 'Phone Extension' },
    { fieldLabel: 'Credentials' },
    { fieldLabel: 'Home Folder (Z: Drive)', fieldType: 'checkbox', fieldOptions: { values: [{ option: 'Set up home folder (Z: drive)' }] } },
    {
      fieldLabel: 'Groups',
      fieldType: 'checkbox',
      fieldOptions: { values: groupOptions }
    }
  ]
};

const workflowObject = {
  name: workflow.name,
  nodes: workflow.nodes,
  connections: workflow.connections || {},
  settings: {}
};

return [{
  json: {
    workflowId: workflow.id,
    workflowObjectJson: JSON.stringify(workflowObject)
  }
}];

const groupNames = $input.all().map(item => String(item.json.cn ?? '').trim()).filter(Boolean);
const uniqueSorted = [...new Set(groupNames)].sort((a, b) => a.localeCompare(b)).map(g => ({ option: g }));

if (uniqueSorted.length === 0) throw new Error('No group options built.');

return [{ json: { dropdownOptions: { groups: uniqueSorted } } }];

